// Accept both Buffer and Uint8Array per spec Section 15.2
onChunk(chunk: ArrayBuffer | Uint8Array | Buffer): void {
  if (this.isTerminal() || this.inputClosed) return;
  if (chunk.byteLength === 0) return;
  if (this.queuedBytes + chunk.byteLength > MAX_QUEUED_BYTES) {
    this.failSession("QueueOverflow", ...);
    return;
  }
  const isAB = chunk instanceof ArrayBuffer;
  const buf = Buffer.from(
    isAB ? chunk : chunk.buffer,
    isAB ? 0 : (chunk as Uint8Array).byteOffset,
    isAB ? chunk.byteLength : (chunk as Uint8Array).byteLength,
  );

private isTerminal(): boolean {
  return (
    this.cancelled ||
    this.state === "final" ||
    this.state === "cancelled" ||
    this.state === "error" ||
    this.state === "budget_exceeded"
  );
}

private postWithPixels(msg: { pixels: ArrayBuffer }, pixels: Buffer): void {
  const ab = pixels.buffer;
  if (pixels.byteOffset === 0 && pixels.byteLength === ab.byteLength) {
    this.port.postMessage(msg, [ab]);
    return;
  }
  const exact = ab.slice(pixels.byteOffset, pixels.byteOffset + pixels.byteLength);
  msg.pixels = exact;
  this.port.postMessage(msg, [exact]);
}

async onCancel(reason?: string): Promise<void> {
  if (this.cancelled || this.state === "done" || this.state === "error") return;
  this.cancelled = true;
  this.state = "cancelled";
  this.wake();

  if (reason !== "release_state") {
    const msg: MsgEncodeCancelled = { type: "encode_cancelled", sessionId: this.sessionId };
    this.port.postMessage(msg);
  }
  this.endSessionOnce();
  void this.disposeActiveEncoder(reason, true);
}

function routeDecodeMessage(msg: QueuedDecodeMessage): void {
  const handler = decodeSessions.get(msg.sessionId);
  if (handler !== undefined) {
    routeToDecodeHandler(handler, msg);
  } else if (pendingDecodeStarts.has(msg.sessionId)) {
    queueDecodeMessage(msg.sessionId, msg);
  }
  // else: silently dropped
}

